import{_ as a,o as i,c as o,ag as c}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Corrección del factor de potencia","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-quality/power-factor-correction.md","filePath":"es/power-quality/power-factor-correction.md"}'),r={name:"es/power-quality/power-factor-correction.md"};function n(t,e,s,l,d,p){return i(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="correccion-del-factor-de-potencia" tabindex="-1">Corrección del factor de potencia <a class="header-anchor" href="#correccion-del-factor-de-potencia" aria-label="Permalink to &quot;Corrección del factor de potencia&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>La corrección del factor de potencia es el proceso de mejorar la eficiencia del uso de potencia al reducir la potencia reactiva en un sistema eléctrico.</p><p>Comúnmente se logra agregando equipo que compensa el componente reactivo de la corriente, permitiendo un uso más efectivo de la potencia disponible.</p><p>Un factor de potencia deficiente conduce a corrientes más altas, mayores pérdidas y capacidad reducida del sistema.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de la corrección del factor de potencia es:</p><ul><li>Reducir el flujo innecesario de corriente en el sistema</li><li>Mejorar la eficiencia energética y reducir las pérdidas</li><li>Incrementar la capacidad disponible de transformadores y conductores</li><li>Evitar penalizaciones de las compañías eléctricas</li><li>Mejorar la estabilidad de voltaje</li></ul><p>Corregir el factor de potencia optimiza el desempeño general del sistema.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>En muchos sistemas industriales, cargas como motores y transformadores consumen tanto potencia activa como potencia reactiva.</p><p>La potencia reactiva no realiza trabajo útil, pero es necesaria para la operación.</p><p>Esto resulta en un factor de potencia menor que 1.</p><p>La corrección del factor de potencia se logra típicamente mediante:</p><ul><li>Instalación de bancos de capacitores que suministran potencia reactiva localmente</li><li>Reducción de la cantidad de potencia reactiva extraída de la fuente</li></ul><p>Al compensar la potencia reactiva:</p><ul><li>La corriente total en el sistema disminuye</li><li>Las caídas de voltaje se reducen</li><li>La eficiencia del sistema mejora</li></ul><p>Los sistemas automáticos pueden conmutar etapas de capacitores según las condiciones de carga.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La corrección del factor de potencia se utiliza en:</p><ul><li>Instalaciones industriales con cargas de motores de gran tamaño</li><li>Sistemas con equipo inductivo, como transformadores y reactores</li><li>Plantas con alto consumo de energía y penalizaciones de la compañía eléctrica</li><li>Sistemas de distribución que requieren mayor eficiencia</li><li>Instalaciones con condiciones de carga fluctuantes</li></ul><p>Se aplica ampliamente tanto en entornos industriales como comerciales.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Factor de potencia objetivo</strong><br> Típicamente cercano a la unidad, pero no necesariamente igual a 1</p></li><li><p><strong>Variabilidad de la carga</strong><br> Las cargas cambiantes requieren sistemas de corrección automáticos o por etapas</p></li><li><p><strong>Interacción con armónicos</strong><br> Los capacitores pueden interactuar con armónicos y crear resonancia</p></li><li><p><strong>Ubicación en el sistema</strong><br> La corrección puede aplicarse de forma centralizada o cerca de cargas individuales</p></li><li><p><strong>Sobrecorrección</strong><br> Una compensación excesiva puede llevar a un factor de potencia adelantado y elevación de voltaje</p></li><li><p><strong>Dimensionamiento del equipo</strong><br> Debe coincidir con los requerimientos de potencia reactiva sin sobredimensionar</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Los bancos de capacitores son la solución más común para la corrección del factor de potencia</li><li>Los sistemas automáticos mejoran el desempeño en condiciones de carga variable</li><li>El análisis armónico es importante antes de instalar capacitores</li><li>Los sistemas mal diseñados pueden crear resonancia y amplificar la distorsión</li><li>La inspección regular garantiza que los capacitores y dispositivos de conmutación operen correctamente</li></ul>',26)])])}const f=a(r,[["render",n]]);export{u as __pageData,f as default};
